<?php
declare(strict_types=1);
require_once __DIR__ . '/_intelligence.php';
$method=strtoupper($_SERVER['REQUEST_METHOD']??'GET');$user=mg_require_permission($method==='GET'?'intelligence.dashboard.view':'intelligence.exports.create');$pdo=mg_db();
if($method==='GET'){$stmt=$pdo->prepare('SELECT public_id,export_type,format,date_from,date_to,privacy_mode,minimum_cohort_size,status,row_count,expires_at,failure_message,created_at,updated_at FROM intelligence_export_jobs WHERE merchant_user_id=? ORDER BY created_at DESC LIMIT 100');$stmt->execute([(int)$user['id']]);mg_ok(['exports'=>$stmt->fetchAll()]);}
if($method!=='POST')mg_fail('Method not allowed.',405);$input=mg_input();mg_require_csrf_for_write($input);$type=trim((string)($input['export_type']??'summary'));$format=trim((string)($input['format']??'csv'));$from=mg_intelligence_date((string)($input['date_from']??''),date('Y-m-d',strtotime('-30 days')));$to=mg_intelligence_date((string)($input['date_to']??''),date('Y-m-d'));$privacy=trim((string)($input['privacy_mode']??'aggregate'));$minimum=max(5,min(1000,(int)($input['minimum_cohort_size']??10)));if(!in_array($type,['summary','daily_facts','forecasts','campaigns','products'],true)||!in_array($format,['csv','json'],true)||!in_array($privacy,['aggregate','k_anonymous'],true)||strtotime($to)<strtotime($from))mg_fail('Invalid export request.',422);$publicId=mg_intelligence_uuid();$pdo->prepare("INSERT INTO intelligence_export_jobs (public_id,merchant_user_id,requested_by_user_id,export_type,format,date_from,date_to,privacy_mode,minimum_cohort_size,status,created_at,updated_at) VALUES (?,?,?,?,?,?,?,?,?,'queued',NOW(),NOW())")->execute([$publicId,(int)$user['id'],(int)$user['id'],$type,$format,$from,$to,$privacy,$minimum]);mg_audit('intelligence.export_queued','intelligence_export_job',['export_id'=>$publicId,'privacy_mode'=>$privacy],(int)$user['id']);mg_ok(['export_id'=>$publicId,'status'=>'queued'],'Intelligence export queued.',202);
